import{_ as n,o as t,c as o,a3 as a}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"41. Change Of Shift Allowance Preservation Ens Only","description":"","frontmatter":{"title":"41. Change Of Shift Allowance Preservation Ens Only","eba":"Nurses and Midwives 2024-2028","topics":["hours","shift-work","allowances"]},"headers":[],"relativePath":"ebas/nurses-midwives/allowances/41-change-of-shift-allowance-preservation-ens-only.md","filePath":"ebas/nurses-midwives/allowances/41-change-of-shift-allowance-preservation-ens-only.md"}'),s={name:"ebas/nurses-midwives/allowances/41-change-of-shift-allowance-preservation-ens-only.md"};function i(r,e,l,p,c,h){return t(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="_41-change-of-shift-allowance-preservation-ens-only" tabindex="-1">41. Change Of Shift Allowance Preservation Ens Only <a class="header-anchor" href="#_41-change-of-shift-allowance-preservation-ens-only" aria-label="Permalink to &quot;41. Change Of Shift Allowance Preservation Ens Only&quot;">​</a></h1><p><strong>41.1</strong> Change of Shift Allowance preservation</p><p>Change of Shift Allowance preservation applies to Existing Employees only. For the purpose of this clause:</p><p><strong>(a)</strong> an Existing Employee is an Employee who was employed as an Enrolled Nurse by an Employer covered by the Nurses and Midwives (Victorian Public Sector) (Single Interest Employers) Enterprise Agreement 2012 – 2016 (2012 Agreement) on 6 July 2012.</p><p><strong>(b)</strong> a Certificate of Service in accordance with <a href="/eba/ebas/nurses-midwives/appendices/06-template-certificate-of-service.html">Appendix 6</a> will constitute acceptable evidence that the Employee is an Existing Employee.</p><p><strong>41.2</strong> Capping of Change of Shift Allowance for Existing Employees</p><p>An Existing Employee will continue to receive the Change of Shift allowance specified in <a href="/eba/ebas/nurses-midwives/appendices/02-wages-and-allowances.html">Appendix 2</a> as follows:</p><p><strong>(a)</strong> An Enrolled Nurse employed by their Employer as at 11 June 2002</p><p>An Existing Employee who is an Enrolled Nurse and was employed by their Employer as at 11 June 2002 will continue to receive two (2) or more change of shift per pay period/fortnight payments in accordance with their existing agreement with their Employer. Such agreement may be in writing or based on custom and practice.</p><p><strong>(b)</strong> Other Existing Employees</p><p><strong>(i)</strong> An Existing Employee who is an Enrolled Nurse, to whom subclause 41.2(a) above does not apply, will continue to have change of shift allowance payments per pay period capped with the cap determined under the 2012 Agreement continuing to apply, except where:</p><p><strong>(A)</strong> an Employee chooses to work fixed shifts and never works shifts that would entitle the Employee to payment under the Nurses (Victorian Public Sector) Multiple Employer Agreement 2004 – 2007, unless a cap historically applied to Employees working fixed shifts; or</p><p><strong>(B)</strong> the Employee commences employment with a new Employer, in which case the applicable cap applies for that ward/area/Campus/health service, whichever is the higher.</p><p><strong>(ii)</strong> For the avoidance of doubt, the process for setting a cap for Employees under this subclause is contained in the 2012 Agreement.</p>',14)])])}const g=n(s,[["render",i]]);export{m as __pageData,g as default};
